const mongoose = require("mongoose");
const logger = require("../utils/logger");

async function connectDb(context = {}) {
  const mongoUri = process.env.MONGO_URI;
  if (!mongoUri) {
    throw new Error("MONGO_URI is missing. Set it in .env");
  }

  if (mongoose.connection.readyState !== 1) {
    try {
      await mongoose.connect(mongoUri);
    } catch (error) {
      logger.error("db-failure", {
        action: "connect",
        correlationId: context.correlationId,
        code: error?.code,
        error
      });
      throw error;
    }
  }
}

module.exports = connectDb;

const { randomUUID } = require("node:crypto");

const CORRELATION_HEADER = "x-correlation-id";
const REQUEST_ID_HEADER = "x-request-id";

function normalizeHeaderValue(value) {
  if (!value) return "";
  if (Array.isArray(value)) return String(value[0] || "").trim();
  return String(value).trim();
}

function correlationId(req, res, next) {
  const incomingCorrelationId = normalizeHeaderValue(req.headers[CORRELATION_HEADER]);
  const incomingRequestId = normalizeHeaderValue(req.headers[REQUEST_ID_HEADER]);
  const id = incomingCorrelationId || incomingRequestId || randomUUID();

  req.correlationId = id;
  res.setHeader("X-Correlation-Id", id);
  next();
}

module.exports = correlationId;

const logger = require("../utils/logger");

function requestLogger(req, res, next) {
  const start = process.hrtime.bigint();

  res.on("finish", () => {
    const end = process.hrtime.bigint();
    const durationMs = Number(end - start) / 1_000_000;

    logger.info("api-call", {
      method: req.method,
      path: req.originalUrl,
      status: res.statusCode,
      durationMs: Math.round(durationMs * 100) / 100
    });
  });

  next();
}

module.exports = requestLogger;

const logger = require("../utils/logger");

function requestLogger(req, res, next) {
  const start = process.hrtime.bigint();
  const correlationId = req.correlationId || "n/a";

  res.on("finish", () => {
    const end = process.hrtime.bigint();
    const durationMs = Number(end - start) / 1_000_000;

    logger.info("api-call", {
      correlationId,
      method: req.method,
      path: req.originalUrl,
      status: res.statusCode,
      durationMs: Math.round(durationMs * 100) / 100,
      ip: req.ip,
      userAgent: req.get("user-agent") || ""
    });
  });

  next();
}

module.exports = requestLogger;

function log(level, message, meta = {}) {
  const payload = {
    ts: new Date().toISOString(),
    level,
    message,
    ...meta
  };
  const line = JSON.stringify(payload);
  if (level === "error") {
    console.error(line);
    return;
  }
  console.log(line);
}

function info(message, meta) {
  log("info", message, meta);
}

function error(message, meta) {
  log("error", message, meta);
}

module.exports = {
  info,
  error
};

function log(level, message, meta = {}) {
  const error = meta.error;
  const safeMeta = { ...meta };
  delete safeMeta.error;

  const payload = {
    ts: new Date().toISOString(),
    level,
    service: "sprint-cc-backend",
    env: process.env.NODE_ENV || "development",
    pid: process.pid,
    message,
    ...safeMeta
  };

  if (error instanceof Error) {
    payload.error = {
      name: error.name,
      message: error.message,
      stack: error.stack
    };
  }

  const line = JSON.stringify(payload);
  if (level === "error") {
    console.error(line);
    return;
  }
  console.log(line);
}

function info(message, meta) {
  log("info", message, meta);
}

function error(message, meta) {
  log("error", message, meta);
}

module.exports = {
  info,
  error
};

const test = require("node:test");
const assert = require("node:assert/strict");
const request = require("supertest");
const mongoose = require("mongoose");
const { MongoMemoryServer } = require("mongodb-memory-server");

let mongo;
let app;

async function closeConnections() {
  await mongoose.connection.dropDatabase();
  await mongoose.connection.close();
  await mongo.stop();
}

test("backend upserts and reads submissions", async (t) => {
  mongo = await MongoMemoryServer.create();
  process.env.MONGO_URI = mongo.getUri();
  process.env.VERCEL = "1";

  app = require("../server");

  t.after(async () => {
    await closeConnections();
  });

  const payload = {
    Team: "McLaren",
    ProjectKey: "MC",
    SprintNo: "35.1",
    PI: "35",
    submittedDate: "2026-06-22",
    submittedBy: "Test User",
    TeamSize: 1,
    TotalDays: 8,
    SprintOverhead: 1.6,
    SprintCapacity: 6.4,
    DevCapacityDays: 6.4,
    TestCapacityDays: 0,
    DevPercent: 100,
    TestPercent: 0,
    Notes: "First submit",
    Roster: [
      { name: "Alice", role: "Full Stack Dev", ph: 0, al: 0, other: 0, pct: 100, notes: "", AvailableDays: 8 }
    ]
  };

  const first = await request(app).post("/api/submissions/upsert").send(payload);
  assert.equal(first.status, 200);
  assert.equal(first.body.success, true);
  assert.equal(first.body.isReplace, false);

  const read = await request(app).get("/api/submissions/MC/35.1");
  assert.equal(read.status, 200);
  assert.equal(read.body.found, true);
  assert.equal(read.body.record.Team, "McLaren");

  const second = await request(app)
    .post("/api/submissions/upsert")
    .send({ ...payload, Notes: "Second submit" });
  assert.equal(second.status, 200);
  assert.equal(second.body.isReplace, true);

  const list = await request(app).get("/api/submissions");
  assert.equal(list.status, 200);
  assert.equal(Array.isArray(list.body), true);
  assert.equal(list.body.length, 1);
  assert.equal(list.body[0].Notes, "Second submit");
});

const test = require("node:test");
const assert = require("node:assert/strict");
const request = require("supertest");
const mongoose = require("mongoose");
const { MongoMemoryServer } = require("mongodb-memory-server");

let mongo;
let app;

async function closeConnections() {
  await mongoose.connection.dropDatabase();
  await mongoose.connection.close();
  await mongo.stop();
}

test("backend upserts and reads submissions", async (t) => {
  mongo = await MongoMemoryServer.create();
  process.env.MONGO_URI = mongo.getUri();
  process.env.VERCEL = "1";

  app = require("../server");

  t.after(async () => {
    await closeConnections();
  });

  const payload = {
    Team: "McLaren",
    ProjectKey: "MC",
    SprintNo: "35.1",
    PI: "35",
    submittedDate: "2026-06-22",
    submittedBy: "Test User",
    TeamSize: 1,
    TotalDays: 8,
    SprintOverhead: 1.6,
    SprintCapacity: 6.4,
    DevCapacityDays: 6.4,
    TestCapacityDays: 0,
    DevPercent: 100,
    TestPercent: 0,
    Notes: "First submit",
    Roster: [
      { name: "Alice", role: "Full Stack Dev", ph: 0, al: 0, other: 0, pct: 100, notes: "", AvailableDays: 8 }
    ]
  };

  const first = await request(app).post("/api/submissions/upsert").send(payload);
  assert.equal(first.status, 200);
  assert.equal(first.body.success, true);
  assert.equal(first.body.isReplace, false);
  assert.ok(first.headers["x-correlation-id"]);

  const read = await request(app)
    .get("/api/submissions/MC/35.1")
    .set("x-correlation-id", "test-corr-id");
  assert.equal(read.status, 200);
  assert.equal(read.body.found, true);
  assert.equal(read.body.record.Team, "McLaren");
  assert.equal(read.headers["x-correlation-id"], "test-corr-id");

  const second = await request(app)
    .post("/api/submissions/upsert")
    .send({ ...payload, Notes: "Second submit" });
  assert.equal(second.status, 200);
  assert.equal(second.body.isReplace, true);

  const list = await request(app).get("/api/submissions");
  assert.equal(list.status, 200);
  assert.equal(Array.isArray(list.body), true);
  assert.equal(list.body.length, 1);
  assert.equal(list.body[0].Notes, "Second submit");
});
